-- TOC entry 296 (class 1255 OID 16834)
-- Name: get_messages(uuid, integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_messages(p_conversation_id uuid, p_limit integer DEFAULT 20, p_offset integer DEFAULT 0) RETURNS TABLE(message_id uuid, content text, message_type text, created_at timestamp without time zone, sender_name text, sender_avatar text)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        m.id,
        m.content,
        m.message_type,
        m.created_at,
        u.full_name,
        u.avatar_url
    FROM messages m
    LEFT JOIN users u ON u.id = m.sender_id
    WHERE m.conversation_id = p_conversation_id
      AND m.is_deleted = FALSE
    ORDER BY m.created_at DESC
    LIMIT GREATEST(p_limit, 1)
    OFFSET GREATEST(p_offset, 0);
END;
$$;


ALTER FUNCTION public.get_messages(p_conversation_id uuid, p_limit integer, p_offset integer) OWNER TO postgres;

--
-- TOC entry 295 (class 1255 OID 16833)
-- Name: get_user_conversations(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_user_conversations(p_user_id uuid) RETURNS TABLE(conversation_id uuid, name text, type text, last_message text, last_time timestamp without time zone, sender_name text, sender_avatar text, unread_count bigint)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        c.id,
        c.name,
        c.type,

        m.content,
        m.created_at,

        u.full_name,
        u.avatar_url,

        COALESCE(unread.unread_count, 0)

    FROM conversations c

    JOIN conversation_members cm 
        ON cm.conversation_id = c.id
        AND cm.user_id = p_user_id

    -- chỉ lấy message chưa bị xóa
    LEFT JOIN LATERAL (
        SELECT m1.*
        FROM messages m1
        WHERE m1.conversation_id = c.id
          AND m1.is_deleted = FALSE
        ORDER BY m1.created_at DESC
        LIMIT 1
    ) m ON TRUE

    LEFT JOIN users u ON u.id = m.sender_id

    -- unread count chuẩn hơn
    LEFT JOIN (
        SELECT 
            m2.conversation_id,
            ms.user_id,
            COUNT(*) AS unread_count
        FROM message_status ms
        JOIN messages m2 ON m2.id = ms.message_id
        WHERE ms.status IN ('sent','delivered') -- tránh scan thừa
        GROUP BY m2.conversation_id, ms.user_id
    ) unread
        ON unread.conversation_id = c.id
        AND unread.user_id = p_user_id

    ORDER BY m.created_at DESC NULLS LAST; -- tránh NULL lên đầu
END;
$$;


