--
-- TOC entry 298 (class 1255 OID 16836)
-- Name: mark_messages_as_read(uuid, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.mark_messages_as_read(p_conversation_id uuid, p_user_id uuid) RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
    UPDATE message_status ms
    SET status = 'read',
        updated_at = CURRENT_TIMESTAMP
    FROM messages m
    WHERE ms.message_id = m.id
      AND m.conversation_id = p_conversation_id
      AND ms.user_id = p_user_id
      AND ms.status IN ('sent','delivered'); -- tối ưu hơn
END;
$$;


