--
-- TOC entry 297 (class 1255 OID 16835)
-- Name: send_message(uuid, uuid, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.send_message(p_conversation_id uuid, p_sender_id uuid, p_content text) RETURNS uuid
    LANGUAGE plpgsql
    AS $$
DECLARE
    new_message_id UUID;
BEGIN
    -- validate basic
    IF p_content IS NULL OR LENGTH(TRIM(p_content)) = 0 THEN
        RAISE EXCEPTION 'Message content cannot be empty';
    END IF;

    -- insert message
        conversation_id,
        sender_id,
        content,
        message_type
    )
    VALUES (
        p_conversation_id,
        p_sender_id,
        p_content,
        'TEXT'
    )
    RETURNING id INTO new_message_id;

    -- insert status cho ALL members (quan trọng)
    SELECT 
        new_message_id,
        cm.user_id,
        CASE 
            WHEN cm.user_id = p_sender_id THEN 'read'
            ELSE 'sent'
        END
    FROM conversation_members cm
    WHERE cm.conversation_id = p_conversation_id;

    RETURN new_message_id;
END;
$$;


ALTER FUNCTION public.send_message(p_conversation_id uuid, p_sender_id uuid, p_content text) OWNER TO postgres;

